const CHAP_NUM = Object.fromEntries(CHAPTERS.map((c) => [c.id, c.num]));
const CHAP_TITLE = Object.fromEntries(CHAPTERS.map((c) => [c.id, c.title]));
function findFormula(chId, refId) {
  const c = CHAPTERS.find((x) => x.id === chId);
  if (!c || !c.formulas) return null;
  return c.formulas.find((f) => f.id === refId) || null;
}

function Frac({ n, d }) {
  return (
    <span style={S.frac}>
      <span style={S.fracN}>{n}</span>
      <span style={S.fracD}>{d}</span>
    </span>
  );
}
function Fx({ parts, plain }) {
  if (!parts) return <span style={S.fxPlain}>{plain}</span>;
  return (
    <div style={S.fxWrap}>
      {parts.map((line, i) => {
        const txt = line.filter((s) => typeof s === "string").join("");
        const rtl = /[\u0600-\u06FF]/.test(txt);
        return (
          <div key={i} style={{ ...S.fxLine, direction: rtl ? "rtl" : "ltr" }}>
            {line.map((seg, j) => (typeof seg === "string" ? <span key={j}>{seg}</span> : <Frac key={j} n={seg.n} d={seg.d} />))}
          </div>
        );
      })}
    </div>
  );
}
function Steps({ steps }) {
  const lastIdx = (() => { let k = -1; steps.forEach((s, i) => { if (!s.n) k = i; }); return k; })();
  let num = 0;
  return (
    <div style={S.storyWrap}>
      {steps.map((st, i) => {
        if (st.n) {
          const warn = st.n.startsWith("⚠️");
          return (
            <div key={i} style={S.stepRow}>
              <div style={S.noteIcon}>{warn ? "⚠️" : "💡"}</div>
              <div style={{ ...S.noteCard, ...(warn ? S.noteCardWarn : {}) }}>{st.n.replace(/^[⚠️💡]+\s*/u, "")}</div>
            </div>
          );
        }
        num += 1;
        const isFinal = i === lastIdx;
        return (
          <div key={i} style={{ ...S.stepRow, ...(isFinal ? {} : S.stepRowLine) }}>
            <div style={{ ...S.stepNum, ...(isFinal ? S.stepNumFinal : {}) }}>{isFinal ? "✓" : num}</div>
            <div style={{ ...S.stepCard, ...(isFinal ? S.stepCardFinal : {}) }}>
              <div style={{ ...S.stepWhat, ...(isFinal ? S.stepWhatFinal : {}) }}>{st.t}</div>
              {st.w && <div style={S.stepWhy}>{st.w}</div>}
              {st.c && <div style={S.stepCalc}>{st.c}</div>}
            </div>
          </div>
        );
      })}
    </div>
  );
}

function VarLines({ vars, legend }) {
  const rows = vars && vars.length ? vars : (legend ? legend.split(" · ") : []);
  if (!rows.length) return null;
  return <div style={S.varsWrap}>{rows.map((r, i) => <div key={i} style={S.varRow}>{r}</div>)}</div>;
}


export default function App() {
  const [store, setStore] = useState({});
  const [loaded, setLoaded] = useState(false);
  const [activeChapter, setActiveChapter] = useState(null); // null = الشاشة الرئيسية
  const [examMode, setExamMode] = useState(false);
  const [dawraList, setDawraList] = useState(false);
  const [activeDawra, setActiveDawra] = useState(null);
  const [storyMode, setStoryMode] = useState(false);
  const [tab, setTab] = useState("quiz");

  useEffect(() => {
    (async () => {
      try {
        const res = await window.storage.get(STORE_KEY);
        if (res && res.value) setStore(JSON.parse(res.value));
      } catch (e) { /* لا يوجد تقدّم بعد */ }
      finally { setLoaded(true); }
    })();
  }, []);

  const persist = useCallback(async (next) => {
    try { await window.storage.set(STORE_KEY, JSON.stringify(next)); } catch (e) { /* تجاهل */ }
  }, []);

  const saveScore = (chId, pct) => {
    const prev = (store[chId] || {}).bestPct;
    const best = prev == null ? pct : Math.max(prev, pct);
    const next = { ...store, [chId]: { ...(store[chId] || {}), bestPct: best } };
    setStore(next); persist(next);
  };
  const saveExamScore = (pct) => {
    const prev = store.__exam__?.bestPct;
    const best = prev == null ? pct : Math.max(prev, pct);
    const next = { ...store, __exam__: { bestPct: best } };
    setStore(next); persist(next);
  };
  const saveDawraScore = (dId, pct) => {
    const prev = store.__dawrat__?.[dId];
    const best = prev == null ? pct : Math.max(prev, pct);
    const next = { ...store, __dawrat__: { ...(store.__dawrat__ || {}), [dId]: best } };
    setStore(next); persist(next);
  };
  const resetAll = () => { setStore({}); persist({}); };

  if (!loaded) return <div dir="rtl" style={{ ...S.root, padding: 40 }}><style>{CSS}</style><div style={S.muted}>...تحميل</div></div>;

  // ===== دورة نشطة (نموذج امتحان بالترتيب) =====
  if (activeDawra) {
    const d = DAWRAT.find((x) => x.id === activeDawra);
    return (
      <div dir="rtl" style={S.root}>
        <style>{CSS}</style>
        <SubHeader title={`دورة ${d.label}`} subtitle={`${d.questions.length} سؤال · بالترتيب كما وردت`} onBack={() => setActiveDawra(null)} />
        <main style={S.main}>
          <Quiz key={d.id} pool={d.questions} bestScore={store.__dawrat__?.[d.id] ?? null} onFinish={(pct) => saveDawraScore(d.id, pct)} ordered dawra />
        </main>
      </div>
    );
  }

  // ===== قائمة الدورات =====
  if (dawraList) {
    return (
      <div dir="rtl" style={S.root}>
        <style>{CSS}</style>
        <SubHeader title="أسئلة الدورات" subtitle="نماذج امتحانات سابقة محلولة ومربوطة بالفصول" onBack={() => setDawraList(false)} />
        <main style={S.main}>
          <div style={S.homeLead}>كل دورة قائمة بذاتها — تُعرض بالترتيب كما وردت، مع ربط كل سؤال بفصله وقانونه.</div>
          <div style={S.chapGrid}>
            {DAWRAT.map((d) => {
              const best = store.__dawrat__?.[d.id];
              return (
                <button key={d.id} className="chap" style={S.chapCard} onClick={() => setActiveDawra(d.id)}>
                  <div style={S.chapTop}>
                    <span style={S.chapNum}>دورة</span>
                    <span style={S.chapKind}>{d.date}</span>
                  </div>
                  <div style={S.chapTitle}>{d.label}</div>
                  <div style={S.chapMeta}>
                    <span>{d.questions.length} سؤال</span>
                    {best != null && <span style={S.chapBest}>أفضل نتيجة {best}%</span>}
                  </div>
                </button>
              );
            })}
          </div>
        </main>
      </div>
    );
  }

  // ===== القصة وراء القوانين =====
  if (storyMode) {
    return (
      <div dir="rtl" style={S.root}>
        <style>{CSS}</style>
        <SubHeader title="القصة وراء القوانين" subtitle="كل قانون بقصة بسيطة تفهمها وتكتبها بإيدك" onBack={() => setStoryMode(false)} />
        <main style={S.main}>
          <Stories />
        </main>
      </div>
    );
  }

  // ===== الامتحان الشامل =====
  if (examMode) {
    const allQ = CHAPTERS.flatMap((c) => c.quiz.map((q) => ({ ...q, _ch: c.num, ch: c.id })));
    return (
      <div dir="rtl" style={S.root}>
        <style>{CSS}</style>
        <SubHeader title="الامتحان الشامل" subtitle={`${allQ.length} سؤال من كل الفصول`} onBack={() => setExamMode(false)} />
        <main style={S.main}>
          <Quiz key="exam" pool={allQ} bestScore={store.__exam__?.bestPct ?? null} onFinish={saveExamScore} showChapter />
        </main>
      </div>
    );
  }

  // ===== الشاشة الرئيسية =====
  if (!activeChapter) {
    return (
      <div dir="rtl" style={S.root}>
        <style>{CSS}</style>
        <header style={S.header}>
          <div style={S.headerInner}>
            <div style={S.kicker}>جامعة دمشق · كلية التجارة والاقتصاد</div>
            <h1 style={S.title}>إدارة الاستثمار والمحافظ الاستثمارية</h1>
            <div style={S.subtitle}>السنة الرابعة · منصة المراجعة قبل الامتحان</div>
            <div style={S.goldBar} />
          </div>
        </header>
        <div style={S.statsRow}>
          <div style={S.statBox}><div style={S.statNum}>{CHAPTERS.length}</div><div style={S.statLbl}>فصول</div></div>
          <div style={S.statBox}><div style={S.statNum}>{CHAPTERS.reduce((n, c) => n + c.quiz.length, 0)}</div><div style={S.statLbl}>سؤال فصول</div></div>
          <div style={S.statBox}><div style={S.statNum}>{DAWRAT.length}</div><div style={S.statLbl}>دورات</div></div>
          <div style={S.statBox}><div style={S.statNum}>{DAWRAT.reduce((n, d) => n + d.questions.length, 0)}</div><div style={S.statLbl}>سؤال دورات</div></div>
        </div>
        <main style={S.main}>
          <div style={S.homeLead}>اختر فصلاً للمراجعة، أو جرّب الامتحان الشامل الذي يسحب أسئلة من كل الفصول.</div>
          <div style={S.chapGrid}>
            {CHAPTERS.map((c) => {
              const st = store[c.id] || {};
              return (
                <button key={c.id} className="chap" style={S.chapCard}
                  onClick={() => { setActiveChapter(c.id); setTab("quiz"); }}>
                  <div style={S.chapTop}>
                    <span style={S.chapNum}>الفصل {c.num}</span>
                    <span style={S.chapKind}>{c.kind}</span>
                  </div>
                  <div style={S.chapTitle}>{c.title}</div>
                  <div style={S.chapMeta}>
                    <span>{c.quiz.length} سؤال{c.formulas && c.formulas.length ? ` · ${c.formulas.length} قانون` : ""}</span>
                    {st.bestPct != null && <span style={S.chapBest}>أفضل نتيجة {st.bestPct}%</span>}
                  </div>
                </button>
              );
            })}
          </div>

          <button className="cta" style={S.examBtn} onClick={() => setExamMode(true)}>
            الامتحان الشامل
            <span style={S.examHint}>{CHAPTERS.reduce((n, c) => n + c.quiz.length, 0)} سؤال من كل الفصول عشوائياً</span>
          </button>

          <button className="cta" style={S.dawraBtn} onClick={() => setDawraList(true)}>
            أسئلة الدورات
            <span style={S.examHint}>{DAWRAT.length} دورة · نماذج امتحانات محلولة ومربوطة بالفصول</span>
          </button>

          <button className="cta" style={S.storyBtn} onClick={() => setStoryMode(true)}>
            القصة وراء القوانين
            <span style={S.examHint}>{STORIES.reduce((n, f) => n + f.laws.length, 0)} قانوناً بقصة بسيطة — افهمها بدل ما تحفظها</span>
          </button>

          <div style={S.soonNote}>يُضاف كل فصل جديد هنا فور تجهيزه — الفصول القادمة في الطريق.</div>
          <button className="linkBtn" style={S.resetBtn} onClick={resetAll}>تصفير كل التقدّم</button>
        </main>
      </div>
    );
  }

  // ===== داخل فصل =====
  const ch = CHAPTERS.find((c) => c.id === activeChapter);
  const st = store[ch.id] || {};
  const hasFormulas = ch.formulas && ch.formulas.length > 0;
  const tabs = [["quiz", "اختبار"]];
  if (hasFormulas) tabs.push(["formulas", "القوانين"]);
  const activeTab = tab === "cards" ? "quiz" : tab;

  return (
    <div dir="rtl" style={S.root}>
      <style>{CSS}</style>
      <SubHeader title={`الفصل ${ch.num}`} subtitle={ch.title} onBack={() => setActiveChapter(null)} />
      <nav style={S.tabs}>
        {tabs.map(([k, label]) => (
          <button key={k} onClick={() => setTab(k)} className="tabBtn" style={{ ...S.tab, ...(activeTab === k ? S.tabActive : {}) }}>{label}</button>
        ))}
      </nav>
      <main style={S.main}>
        {activeTab === "formulas" && hasFormulas
          ? <Formulas formulas={ch.formulas} showConstNote={ch.id === "ch2"} />
          : <Quiz key={ch.id} pool={ch.quiz} bestScore={st.bestPct ?? null} onFinish={(pct) => saveScore(ch.id, pct)} chId={ch.id} />}
      </main>
    </div>
  );
}

function SubHeader({ title, subtitle, onBack, pct }) {
  return (
    <header style={S.header}>
      <div style={{ flex: 1 }}>
        <button className="linkBtn" style={S.backBtn} onClick={onBack}>→ رجوع</button>
        <h1 style={{ ...S.title, fontSize: 26, marginTop: 6 }}>{title}</h1>
        <div style={S.subtitle}>{subtitle}</div>
      </div>
      {pct != null && (
        <div style={S.ring} aria-label={`نسبة الإتقان ${pct}%`}>
          <svg viewBox="0 0 100 100" width="66" height="66">
            <circle cx="50" cy="50" r="42" fill="none" stroke="#25534a" strokeWidth="8" />
            <circle cx="50" cy="50" r="42" fill="none" stroke="#d9a536" strokeWidth="8" strokeLinecap="round"
              strokeDasharray={`${(pct / 100) * 264} 264`} transform="rotate(-90 50 50)" style={{ transition: "stroke-dasharray .5s ease" }} />
          </svg>
          <div style={S.ringLabel}><div style={{ ...S.ringPct, fontSize: 15 }}>{pct}%</div></div>
        </div>
      )}
    </header>
  );
}


function Quiz({ pool, bestScore, onFinish, showChapter, ordered, dawra, chId }) {
  const [phase, setPhase] = useState(ordered ? "run" : "setup");
  const [items, setItems] = useState(ordered ? [...pool] : []);
  const [answers, setAnswers] = useState(ordered ? pool.map(() => null) : []);
  const [step, setStep] = useState(0);
  const [showRef, setShowRef] = useState(false);

  const hasNumeric = pool.some((q) => q.solution);
  const hasTheory = pool.some((q) => !q.solution);

  const start = (mode, count) => {
    let p = [...pool];
    if (mode === "numeric") p = pool.filter((q) => q.solution);
    else if (mode === "theory") p = pool.filter((q) => !q.solution);
    if (!ordered) p = shuffleGrouped(p);
    if (count && count !== "all") p = p.slice(0, count);
    setItems(p); setAnswers(p.map(() => null)); setStep(0); setShowRef(false); setPhase("run");
  };

  const q = items[step];
  const picked = answers.length ? (answers[step] ?? null) : null;
  const scoreOf = (arr) => arr.reduce((n, a, i) => n + (a !== null && a === items[i].correct ? 1 : 0), 0);
  const numAnswered = answers.filter((a) => a !== null).length;
  const isLast = step + 1 >= items.length;
  const reviewing = phase === "review";

  const choose = (idx) => {
    if (reviewing || answers[step] != null) return;
    setAnswers((a) => { const b = [...a]; b[step] = idx; return b; });
  };
  const goto = (i) => {
    if (i < 0 || i >= items.length) return;
    setStep(i); setShowRef(false);
    try { window.scrollTo({ top: 0, behavior: "smooth" }); } catch (e) { /* */ }
  };
  const finish = () => { setPhase("done"); onFinish(Math.round((scoreOf(answers) / items.length) * 100)); };

  if (phase === "setup") {
    return (
      <div style={S.setupWrap}>
        <div style={S.setupTitle}>اختر نوع الجلسة</div>
        <div style={S.setupSub}>{pool.length} سؤالاً في البنك — تُسحب عشوائياً.</div>
        <div style={S.setupGrid}>
          <button className="cta" style={{ ...S.setupBtn, ...S.setupBtnFull }} onClick={() => start("all")}>الكل · {pool.length} سؤال<span style={S.setupHint}>{showChapter ? "من جميع الفصول" : "نظري + عملي"}</span></button>
          {pool.length > 15 && <button className="cta" style={S.setupBtn} onClick={() => start("all", 15)}>جلسة سريعة · 15 سؤال<span style={S.setupHint}>عيّنة عشوائية</span></button>}
          {hasTheory && hasNumeric && <button className="cta" style={S.setupBtn} onClick={() => start("theory")}>نظري فقط<span style={S.setupHint}>{pool.filter((q) => !q.solution).length} سؤال · مع مصدر الكتاب</span></button>}
          {hasNumeric && <button className="cta" style={S.setupBtn} onClick={() => start("numeric")}>مسائل فقط<span style={S.setupHint}>{pool.filter((q) => q.solution).length} مسائل · مع الحل والقانون</span></button>}
        </div>
        {bestScore !== null && <div style={S.muted}>أفضل نتيجة سابقة: {bestScore}%</div>}
      </div>
    );
  }

  if (phase === "done") {
    const sc = scoreOf(answers);
    const pct = Math.round((sc / items.length) * 100);
    const skipped = items.length - numAnswered;
    const wrong = items.map((it, i) => ({ it, i, a: answers[i] })).filter((x) => x.a !== null && x.a !== x.it.correct);
    // تحليل الضعف حسب الفصل (للشامل والدورات حيث ch متوفر)
    const byCh = {};
    wrong.forEach(({ it }) => { const k = it.ch; if (k) byCh[k] = (byCh[k] || 0) + 1; });
    const weakest = Object.entries(byCh).sort((a, b) => b[1] - a[1]).slice(0, 3);
    return (
      <div style={S.resultWrap}>
        <div style={S.resultRing}><div style={S.resultScore}>{sc}<span style={S.resultOf}>/{items.length}</span></div></div>
        <div style={S.resultPct}>{pct}%</div>
        <div style={S.resultMsg}>
          {pct === 100 ? "علامة كاملة! 🎯" : pct >= 70 ? "أداء قوي — راجع ما أخطأت به." : "راجع القوانين ثم أعد المحاولة."}
        </div>
        {skipped > 0 && <div style={S.muted}>تركت {skipped} سؤالاً بلا إجابة.</div>}
        {bestScore !== null && <div style={S.muted}>أفضل نتيجة لك: {bestScore}%</div>}

        {weakest.length > 0 && (
          <div style={S.weakBox}>
            <div style={S.weakTitle}>ركّز مراجعتك على:</div>
            {weakest.map(([k, n]) => (
              <div key={k} style={S.weakRow}>الفصل {CHAP_NUM[k]} — {CHAP_TITLE[k]} <span style={S.weakCount}>({n} {n === 1 ? "خطأ" : "أخطاء"})</span></div>
            ))}
          </div>
        )}

        {wrong.length > 0 && (
          <div style={S.wrongList}>
            <div style={S.weakTitle}>أخطاؤك ({wrong.length}):</div>
            {wrong.map(({ it, i, a }) => (
              <button key={i} className="chap" style={S.wrongItem} onClick={() => { setStep(i); setShowRef(false); setPhase("review"); }}>
                <div style={S.wrongQ}>{i + 1}. {it.q.length > 70 ? it.q.slice(0, 70) + "…" : it.q}</div>
                <div style={S.wrongA}>إجابتك: {it.options[a]} ✕ · الصحيح: {it.options[it.correct]} ✓</div>
              </button>
            ))}
          </div>
        )}

        <div style={S.ctaRow}>
          <button className="cta" style={S.ctaGhost} onClick={() => { setStep(0); setShowRef(false); setPhase("review"); }}>مراجعة الكل</button>
          <button className="cta" style={S.ctaPrimary} onClick={() => (ordered ? start("all") : setPhase("setup"))}>{ordered ? "إعادة الدورة" : "جلسة جديدة"}</button>
        </div>
      </div>
    );
  }

  const linkedFml = q.ref ? findFormula(q.ch || chId, q.ref) : null;
  const refFormula = showRef && linkedFml ? linkedFml : null;
  return (
    <div style={S.quizWrap}>
      {reviewing && (
        <div style={S.reviewBanner}>
          <span>وضع المراجعة — الإجابات مقفلة</span>
          <button className="linkBtn" style={S.reviewBack} onClick={() => setPhase("done")}>← عودة للنتيجة</button>
        </div>
      )}
      <div style={S.dotsRow}>
        {items.map((it, i) => {
          const a = answers[i];
          const bg = a === null ? "#d7ded9" : a === it.correct ? "#2e9e6b" : "#d9534f";
          return <button key={i} className="dot" onClick={() => goto(i)} style={{ ...S.dot, background: bg, ...(i === step ? S.dotActive : {}) }} aria-label={`سؤال ${i + 1}`} />;
        })}
      </div>
      <div style={S.quizBar}><div style={{ ...S.quizFill, width: `${(step / items.length) * 100}%` }} /></div>
      <div style={S.progressText}>سؤال {step + 1} من {items.length} · أُجيب {numAnswered}/{items.length}{showChapter && q._ch ? ` · الفصل ${q._ch}` : ""}</div>
      {(q.outside || q.ch) && (
        <div style={q.outside ? S.badgeOutside : S.badgeChap}>
          {q.outside ? "⚠ خارج الفصول الثمانية" : `الفصل ${CHAP_NUM[q.ch]} · ${CHAP_TITLE[q.ch]}`}
        </div>
      )}
      {q.context && <div style={S.ctxBox}>{q.context}</div>}
      <div style={S.quizQ}>{q.q}</div>
      <div style={S.opts}>
        {q.options.map((opt, idx) => {
          let stl = { ...S.opt };
          if (picked !== null || reviewing) {
            if (idx === q.correct) stl = { ...stl, ...S.optCorrect };
            else if (idx === picked) stl = { ...stl, ...S.optWrong };
            else stl = { ...stl, ...S.optDim };
          }
          return (
            <button key={idx} className="opt" style={stl} onClick={() => choose(idx)} disabled={picked !== null}>
              <span style={{ ...S.optLetter, ...(picked !== null || reviewing ? (idx === q.correct ? S.optLetterOk : idx === picked ? S.optLetterNo : {}) : {}) }}>{"ABCD"[idx] || "E"}</span>
              <span style={S.optText}>{opt}</span>
              {(picked !== null || reviewing) && idx === q.correct && <span style={S.optMark}>✓</span>}
              {picked !== null && idx === picked && idx !== q.correct && <span style={S.optMark}>✕</span>}
            </button>
          );
        })}
      </div>
      {(picked !== null || reviewing) && (q.solution || q.law || q.source || linkedFml) && (
        <div style={S.reveal}>
          {q.solution && linkedFml && (
            <div style={S.fastBox}>
              <div style={S.fastTag}>⚡ مفتاح الحل السريع</div>
              {linkedFml.parts
                ? (<><Fx parts={linkedFml.parts} /><VarLines vars={linkedFml.vars} legend={linkedFml.legend} />{(linkedFml.tip || linkedFml.fast) && <div style={S.fastTip}>{linkedFml.tip || linkedFml.fast}</div>}</>)
                : (<div style={S.fastBody}>{linkedFml.fast}</div>)}
            </div>
          )}
          {q.law && (<><div style={S.revealTag}>القانون المستخدم</div><div style={S.revealLaw}>{q.law}</div></>)}
          {q.steps ? (<><div style={S.revealTag}>الحل خطوة بخطوة</div><Steps steps={q.steps} /></>) : q.solution ? (<><div style={S.revealTag}>الحل خطوة بخطوة</div><div style={S.revealBody}>{q.solution}</div></>) : null}
          {q.source && (<><div style={S.revealTag}>{q.outside ? "ملاحظة" : "من الكتاب"}</div><div style={S.revealSource}>{q.source}</div></>)}
          {linkedFml && (
            <button className="linkBtn" style={S.refBtn} onClick={() => setShowRef((v) => !v)}>
              {showRef ? "▲ إخفاء القانون" : "▼ راجع القانون كاملاً"}
            </button>
          )}
          {refFormula && (
            <div style={S.refCard}>
              <div style={S.refName}>{refFormula.name}</div>
              {refFormula.parts
                ? (<><Fx parts={refFormula.parts} /><VarLines vars={refFormula.vars} legend={refFormula.legend} />{refFormula.exParts ? <Fx parts={refFormula.exParts} /> : (refFormula.example && <div style={S.refExample}>{refFormula.example}</div>)}</>)
                : (<><div style={S.refSingle}>{refFormula.single}</div>{refFormula.legend && <div style={S.refLegend}>{refFormula.legend}</div>}{refFormula.example && <div style={S.refExample}>{refFormula.example}</div>}</>)}
            </div>
          )}
        </div>
      )}
      <div style={S.navRow}>
        <button className="navc" style={{ ...S.navBtn, ...(step === 0 ? S.navBtnDisabled : {}) }} onClick={() => goto(step - 1)} disabled={step === 0}>◄ السابق</button>
        {!isLast && (
          <button className="navc" style={S.navBtn} onClick={() => goto(step + 1)}>
            {reviewing || picked !== null ? "التالي ►" : "تخطّي ►"}
          </button>
        )}
        {isLast && !reviewing && (
          <button className="cta" style={{ ...S.navBtn, ...S.navFinish }} onClick={finish}>إنهاء ►</button>
        )}
        {isLast && reviewing && (
          <button className="cta" style={{ ...S.navBtn, ...S.navFinish }} onClick={() => setPhase("done")}>عودة للنتيجة</button>
        )}
      </div>
      {!isLast && !reviewing && (
        <button className="linkBtn" style={S.finishLink} onClick={finish}>
          إنهاء الآن وعرض النتيجة{numAnswered < items.length ? ` · باقٍ ${items.length - numAnswered} بلا إجابة` : ""}
        </button>
      )}
    </div>
  );
}

function Formulas({ formulas, showConstNote }) {
  return (
    <div style={S.formWrap}>
      {showConstNote && <div style={S.constNote}><b>مفتاح السرعة:</b> {CONST_NOTE}</div>}
      {formulas.map((f) => (
        <div key={f.id} style={S.formCard}>
          <div style={S.formName}>{f.name}</div>
          <div style={S.formBlockTag}>القانون</div>
          <div style={S.formBook}><Fx parts={f.parts} plain={f.single} /></div>
          <VarLines vars={f.vars} legend={f.legend} />
          <div style={{ ...S.formBlockTag, color: gold }}>طريقة سريعة</div>
          <div style={S.formFast}>{f.tip || f.fast}</div>
          <div style={S.formBlockTag}>مثال محلول</div>
          {f.exParts ? <Fx parts={f.exParts} /> : <div style={S.formExample}>{f.example}</div>}
        </div>
      ))}
    </div>
  );
}

function Stories() {
  const total = STORIES.reduce((n, fam) => n + fam.laws.length, 0);
  return (
    <div style={S.storyPage}>
      <div style={S.storyIntro}>
        <div style={S.storyIntroTitle}>مو حفظ رموز — فهم من وين إجا</div>
        <div style={S.storyIntroBody}>كل قانون هون مترجَم من «طلاسم» لجملة عربية بتفهمها. الطريقة: اقرا القصة، سكّرها واكتب الجملة بإيدك، بعدها افتح مسألة بالمنصة وحلّها مغلّق الحل. لما تمسك القصة، القانون بينكتب لحالو. (ملاحظة: بعض القوانين بالكتاب نفس الصيغة بالضبط برموز مختلفة — متل عائد المحفظة الموزون، والوزن الأمثل — فمعروضة مرة وحدة عشان ما نكرّر عليك.)</div>
      </div>
      {STORIES.map((fam) => (
        <section key={fam.idx} style={S.storyFam}>
          <div style={S.storyFamHead}>
            <span style={S.storyFamIdx}>{fam.idx}</span>
            <div>
              <div style={S.storyFamTitle}>{fam.title}</div>
              <div style={S.storyFamSub}>{fam.sub}</div>
            </div>
          </div>
          {fam.note && <div style={S.storyFamNote}>{fam.note}</div>}
          {fam.laws.map((law, i) => (
            <div key={i} style={S.storyCard}>
              <div style={S.storyCardHead}>
                <div style={S.storyLawName}>{law.name}</div>
                <div style={S.storyLawTag}>{law.tag}</div>
              </div>
              <div style={S.storyFormula}>
                {law.f}
                {law.alt && <span style={S.storyFormulaAlt}>{law.alt}</span>}
              </div>
              <div style={S.storyBlock}>
                <div style={{ ...S.storyBlockLbl, color: green2 }}><span style={S.storyDot} />القصة</div>
                <div style={S.storyText}>{law.s}</div>
              </div>
              <div style={S.storyBlock}>
                <div style={{ ...S.storyBlockLbl, color: gold }}><span style={{ ...S.storyDot, background: gold }} />بتكتبها بإيدك</div>
                <div style={S.storyHand}>{law.h}</div>
              </div>
            </div>
          ))}
        </section>
      ))}
      <div style={S.storyFoot}>{total} قانوناً · 6 عائلات — لما تفهم القصة، القانون بينكتب لحالو.</div>
    </div>
  );
}

function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1)); [a[i], a[j]] = [a[j], a[i]]; }
  return a;
}

// خلط واعٍ بالمجموعات: الأسئلة المتتالية التي تتشارك نفس نص المسألة (context)
// تبقى كتلة واحدة بترتيبها الأصلي، ويجري الخلط على مستوى الكتل فقط.
function shuffleGrouped(arr) {
  const units = [];
  let i = 0;
  while (i < arr.length) {
    if (arr[i].context) {
      const grp = [arr[i]];
      while (i + 1 < arr.length && arr[i + 1].context === arr[i].context) { grp.push(arr[++i]); }
      units.push(grp);
    } else {
      units.push([arr[i]]);
    }
    i++;
  }
  return shuffle(units).flat();
}

